INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('under', 'op', 36, 'OP', '在……下面；少于；受……控制', 'below something or controlled by it', 'The cat is sleeping under the chair.', '猫正在椅子下面睡觉。', '[{"w":"to","def":"to: 相关的动作或关系词","vs":"与 under 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"to\" / \"under\" 的替换练习"},{"w":"up","def":"up: 可帮助扩展句型的基础词","vs":"与 under 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"up\" / \"under\" 的替换练习"},{"w":"with","def":"with: 同一组 Basic English 操作词","vs":"与 under 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"with\" / \"under\" 的替换练习"}]'),
  ('up', 'op', 37, 'OP', '向上；在高处；完成', 'toward or in a higher place or state', 'Stand up when your name is called.', '叫到你的名字时站起来。', '[{"w":"under","def":"under: 相关的动作或关系词","vs":"与 up 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"under\" / \"up\" 的替换练习"},{"w":"with","def":"with: 可帮助扩展句型的基础词","vs":"与 up 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"with\" / \"up\" 的替换练习"},{"w":"as","def":"as: 同一组 Basic English 操作词","vs":"与 up 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"as\" / \"up\" 的替换练习"}]'),
  ('with', 'op', 38, 'OP', '和；带有；使用', 'together with, having, or using something', 'Cut the paper with this knife.', '用这把刀裁纸。', '[{"w":"up","def":"up: 相关的动作或关系词","vs":"与 with 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"up\" / \"with\" 的替换练习"},{"w":"as","def":"as: 可帮助扩展句型的基础词","vs":"与 with 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"as\" / \"with\" 的替换练习"},{"w":"for","def":"for: 同一组 Basic English 操作词","vs":"与 with 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"for\" / \"with\" 的替换练习"}]'),
  ('as', 'op', 39, 'OP', '作为；像；当……时', 'in the role of, in the same way as, or while', 'Use this box as a seat.', '把这个箱子当座位用。', '[{"w":"with","def":"with: 相关的动作或关系词","vs":"与 as 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"with\" / \"as\" 的替换练习"},{"w":"for","def":"for: 可帮助扩展句型的基础词","vs":"与 as 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"for\" / \"as\" 的替换练习"},{"w":"of","def":"of: 同一组 Basic English 操作词","vs":"与 as 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"of\" / \"as\" 的替换练习"}]'),
  ('for', 'op', 40, 'OP', '为了；给；持续；因为', 'show purpose, receiver, time, or reason', 'This warm coat is for the old man.', '这件暖和的外衣是给那位老人用的。', '[{"w":"as","def":"as: 相关的动作或关系词","vs":"与 for 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"as\" / \"for\" 的替换练习"},{"w":"of","def":"of: 可帮助扩展句型的基础词","vs":"与 for 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"of\" / \"for\" 的替换练习"},{"w":"till","def":"till: 同一组 Basic English 操作词","vs":"与 for 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"till\" / \"for\" 的替换练习"}]');
